import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const vex = new Vex({
  projectId: 'fintech-mastra',
  apiKey: process.env.VEX_API_KEY
});

const mastra = new Mastra({
  middleware: {
    async beforeToolCall(context) {
      await vex.check({
        name: 'pci-encryption',
        data: context.input,
        rules: {
          tls_version: '>1.3',
          encrypt_fields: ['pan', 'cvv'],
          block_plaintext_pii: true
        }
      });
    }
  }
});

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const memoryGuard = async (context: any) => {
  const result = await vex.validate({
    name: 'gdpr-memory-freshness',
    data: context.memory,
    rules: {
      data_age_hours: '<24',
      consent_required: true,
      pii_minimization: {
        fields: ['name', 'account'],
        redact_unnecessary: true
      }
    }
  });
  if (!result.valid) {
    throw new Error('GDPR violation: stale or unconsented data');
  }
  return context;
};

const mastra = new Mastra({ middleware: { beforeMemoryRetrieve: memoryGuard } });

import { Vex } from '@vex_dev/sdk';
import { Mastra } from 'mastra';

const complianceMiddleware = {
  async afterAgentResponse(context: any) {
    const checks = await Promise.all([
      vex.check({
        name: 'sec-disclaimer',
        data: context.response,
        rules: { contains_disclaimer: 'Investment advice...risks involved' }
      }),
      vex.validate({
        name: 'aml-screening',
        data: context.tools.aml_result,
        rules: {
          risk_score_explainable: true,
          suspicious_flags: { require_audit: true }
        }
      })
    ]);
    return checks.every(c => c.valid);
  }
};

const mastra = new Mastra({ middleware: complianceMiddleware });
